/* Return the largest sum of any contiguous subarray in the vector x.
   Implementation is a single‑pass Kadane algorithm, which preserves
   the exact result of the original double loop while running in O(n). */

int maximumSubarray(std::vector<int> const& x) {
    if (x.empty())
        return std::numeric_limits<int>::lowest();

    int maxEndingHere = x[0];
    int maxSoFar = x[0];

    for (std::size_t i = 1; i < x.size(); ++i) {
        int val = x[i];
        // If extending the previous subarray is worse than starting new, start here
        if (maxEndingHere < 0)
            maxEndingHere = val;
        else
            maxEndingHere += val;

        if (maxEndingHere > maxSoFar)
            maxSoFar = maxEndingHere;
    }
    return maxSoFar;
}
