/*
 * Replace every element of the vector x with 1-1/x.
 * Example:
 *   input:  [2, 4, 1, 12, -2]
 *   output: [0.5, 0.75, 0, 0.91666666, 1.5]
 */
inline void oneMinusInverse(std::vector<double> &x)
{
    const std::size_t N = x.size();
    if (N == 0) return;

    /* Work on raw data for maximum cache‑friendliness.
     * Use a pointer to avoid multiple bounds checks
     * and let the compiler auto‑vectorise.          */
    double *data = x.data();

    /* Parallel loop – GCC auto‑vectorises the inner loop,
     * but we force parallelism with a barrier-free schedule
     * to avoid thread overhead on tiny vectors.          */
