    for (long long i = 0; i < static_cast<long long>(N); ++i) {
        const double v = data[i];
        /* Handle zero specially to avoid NaN / inf,
         * preserving the original behaviour (1 - 1/0 = -inf).  */
        data[i] = 1.0 - 1.0 / v;
    }
