int edgeCount(std::vector<int> const& A, size_t N) {
    // Use a 64‑bit accumulator to avoid intermediate overflow
    // but ultimately cast to int to match the original signature.
    long long sum = 0;

    // Parallelize the double loop with a single reduction.
    #pragma omp parallel for collapse(1) reduction(+:sum) schedule(static)
    for (size_t i = 0; i < N; ++i) {
