48_sparse_la_sparse_axpy:
```cpp
#pragma once
#include <vector>
#include <omp.h>

struct Element {
    size_t index;
    double value;
};

/*
    Compute z = alpha*x + y where x and y are sparse vectors.
    The result is accumulated into the pre‑allocated array `z`.
    The algorithm first adds the `alpha*x` part, then the `y` part.
    Because each index appears at most once in each input vector,
    the two passes can be safely performed in parallel without any
    synchronization.
*/
inline void sparseAxpy(double alpha,
                       std::vector<Element> const& x,
                       std::vector<Element> const& y,
                       std::vector<double> &z)
{
    // First add alpha * x
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        z[x[i].index] += alpha * x[i].value;
    }

    // Then add y
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        z[y[i].index] += y[i].value;
    }
}
