/*
 * For each letter in the alphabet, count the number of strings in the vector `s`
 * that start with that letter. All strings are assumed to be lower case.
 *
 * The result is stored in the `bins` array (size 26), where
 *   bins[0]  → number of strings starting with 'a'
 *   bins[1]  → number of strings starting with 'b'
 *   …
 *   bins[25] → number of strings starting with 'z'
 *
 * The implementation is fully parallelised with OpenMP and gcc's `-fopenmp`.
 * It preserves the exact behaviour of the reference serial implementation.
 */
void firstLetterCounts(const std::vector<std::string>& s,
                       std::array<std::size_t, 26>& bins)
{
    // Ensure the output array is zero‑initialised (exact behaviour required).
    bins.fill(0);

    // Parallel reduction over a fixed‑size array (gcc supports element‑wise reduction).
    #pragma omp parallel for reduction(+:bins[:26])
    for (std::size_t i = 0; i < s.size(); ++i) {
        const char c   = s[i][0];          // first character (assumed lower‑case)
        const int  idx = c - 'a';          // index 0..25
        bins[static_cast<std::size_t>(idx)] += 1;
    }
}
