/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
*/
inline void pixelCounts(std::vector<int> const& image,
                        std::array<std::size_t, 256>& bins) {
    // Ensure bins are zeroed in case the caller didn't
    std::fill(bins.begin(), bins.end(), 0);

    // Get number of threads from OpenMP environment
    int const nthreads = omp_get_max_threads();

    // Allocate per‑thread local bins
    std::vector<std::array<std::size_t, 256>> local(nthreads);

    #pragma omp parallel
    {
        int const tid = omp_get_thread_num();
        auto& localBins = local[tid];
        // localBins are automatically zero‑initialized by vector ctor

        #pragma omp for schedule(static)
        for (std::size_t idx = 0; idx < image.size(); ++idx) {
            ++localBins[static_cast<unsigned char>(image[idx])];
        }
    }

    // Merge per‑thread results into the output array
    for (int t = 0; t < nthreads; ++t) {
        const auto& lb = local[t];
        for (int val = 0; val < 256; ++val) {
            bins[val] += lb[val];
        }
    }
