16_graph_largest_component:
```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <numeric>
#include <omp.h>

struct DSU {
    std::vector<int> parent;
    std::vector<int> sz;
    DSU(int n): parent(n), sz(n,1) {
        std::iota(parent.begin(), parent.end(), 0);
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        int ra = find(a);
        int rb = find(b);
        if (ra == rb) return;
        if (sz[ra] < sz[rb]) std::swap(ra, rb);
        parent[rb] = ra;
        sz[ra] += sz[rb];
    }
    int component_size(int x) {
        return sz[find(x)];
    }
};

int largestComponent(std::vector<int> const& A, size_t N) {
    DSU dsu(N);
    // Parallel union of edges
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < (int)N; ++i) {
        int base = i * (int)N;
        for (int j = 0; j < (int)N; ++j) {
            if (A[base + j]) dsu.unite(i, j);
        }
    }
    // Gather component sizes
    std::vector<int> compSize(N, 0);
    #pragma omp parallel for schedule(static)
    for (int i = 0; i < (int)N; ++i) {
        int root = dsu.find(i);
        #pragma omp atomic
        compSize[root] += 1;
    }
    return *std::max_element(compSize.begin(), compSize.end());
}
