#include <algorithm>
#include <omp.h>

/*
 * Vector `x` contains values between 0 and 100, inclusive.
 * Count the number of values in the ranges
 *   [0,10), [10,20), …, [90,100]
 * and store the counts in `bins`.
 * Example:
 *   input : [7, 32, 95, 12, 39, 32, 11, 71, 70, 66]
 *   output: [1, 2, 0, 3, 0, 0, 1, 2, 0, 1]
 */
inline void binsBy10Count(std::vector<double> const& x, std::array<std::size_t, 10>& bins) {
    // Zero the result array
    std::fill(bins.begin(), bins.end(), 0);

    // Temporary per‑thread storage to avoid false sharing and atomics
    const int nthreads = omp_get_max_threads();
    std::vector<std::array<std::size_t, 10>> local_bins(nthreads);
    for (auto& arr : local_bins) std::fill(arr.begin(), arr.end(), 0);

    // Parallel loop: static chunking gives good load balance for massive inputs
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto &tmp = local_bins[tid];

        #pragma omp for schedule(static)
        for (std::size_t i = 0; i < x.size(); ++i) {
            // Safe to cast to size_t after division
            const size_t bin = static_cast<size_t>(x[i] / 10.0);
            ++tmp[bin];
        }
    }

    // Reduce per‑thread results into the output array
    for (int t = 0; t < nthreads; ++t)
        for (int b = 0; b < 10; ++b)
            bins[b] += local_bins[t][b];
}
