```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/*
 * Optimised SpMM:
 *   Y = A * X
 *   A : M × K sparse matrix in COO format
 *   X : K × N sparse matrix in COO format
 *   Y : M × N dense matrix (row‑major)
 *
 * The algorithm first hashes the non‑zeros of X by the row index
 * (i.e. the "K" dimension).  Then, for every entry of A, the
 * corresponding list of X entries is fetched in O(1) time and the
 * partial products are accumulated.  The final result is accumulated
 * into Y using an OpenMP parallel block with atomic updates to avoid
 * race conditions.
 *
 * The implementation preserves the exact semantics of the naïve
 * reference but achieves a significant speedup on modern CPUs.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N) {
    // Initialise Y
    Y.assign(M * N, 0.0);

    // Build a hash map from X.row to the list of (col,value) pairs
    // This allows O(1) lookup of the column/value for a given row.
    std::vector<std::vector<std::pair<size_t,double>>> XbyRow(K);
    for (const auto& e : X) {
        XbyRow[e.row].emplace_back(e.column, e.value);
    }

    // Parallel over the non‑zeros of A
    #pragma omp parallel for schedule(dynamic, 1024)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& a = A[i];
        const auto& target = XbyRow[a.column];
        if (target.empty()) continue;

        double aVal = a.value;
        for (const auto& xv : target) {
            size_t col = xv.first;
            double prod = aVal * xv.second;
            // Row‑major: index = a.row * N + col
            size_t idx = a.row * N + col;

            // Atomic add to avoid data races
            #pragma omp atomic
            Y[idx] += prod;
        }
    }
}
