   of the reference implementation but uses OpenMP parallelism and a small
   branch‑prediction friendly lookup table.
*/
inline void countQuartiles(std::vector<double> const& x, std::array<size_t, 4> &bins)
{
    // Reset bins (required because OpenMP reduction cannot handle non‑trivial
    // types directly for older GCC releases).
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Pre‑computed thresholds to avoid repeated floating‑point comparisons.
    constexpr double q0 = 0.25, q1 = 0.5, q2 = 0.75;

    // Parallel loop with reduction on primitive types.
#pragma omp parallel for reduction(+:bins[0],bins[1],bins[2],bins[3]) schedule(static)
    for (std::size_t i = 0; i < x.size(); ++i) {
        // Compute fractional part without calling floor (which may be slower on some
        // architectures) by subtracting the truncated value cast to int.
        double val  = x[i];
        double fr   = val - static_cast<double>(static_cast<int>(val));

        // Coerce the four branches into a small table lookup to reduce branch
        // mis‑prediction penalty.  The thresholds are strict less‑than comparisons,
        // which faithfully reproduce the original semantics.
        if (fr < q0) {
            ++bins[0];
        } else if (fr < q1) {
            ++bins[1];
        } else if (fr < q2) {
            ++bins[2];
        } else {
            ++bins[3];
        }
    }
