   x and y are length N and A is M x N.  The function preserves the
   exact behavior of the original implementation while using
   OpenMP to gain speed on an 8‑thread x86‑64 machine.
*/
inline void spmv(double alpha,
                 const std::vector<COOElement>& A,
                 const std::vector<double>& x,
                 double beta,
                 std::vector<double>& y,
                 size_t M,
                 size_t N) {
    // --------------------------------------------------------------------
    // Stage 1: scale y by beta.  Parallelise this straightforward loop.
    // --------------------------------------------------------------------
    #pragma omp parallel for schedule(static)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(y.size()); ++i) {
        y[static_cast<size_t>(i)] *= beta;
    }

    // --------------------------------------------------------------------
    // Stage 2: multiply and accumulate A * x into y.
    //   Use per‑thread local accumulation to avoid false sharing.
    // --------------------------------------------------------------------
    const int nthreads = omp_get_max_threads();
    std::vector<std::vector<double>> local_y(nthreads, std::vector<double>(M, 0.0));

    // Parallel reduction over A.  Each thread writes only to its
    // own slot in local_y, so no atomic ops are needed.
    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double>& y_local = local_y[tid];

        #pragma omp for schedule(static)
        for (ptrdiff_t k = 0; k < static_cast<ptrdiff_t>(A.size()); ++k) {
            const COOrdElement& a_ij = A[static_cast<size_t>(k)];
            if (a_ij.row < M && a_ij.column < N) {
                y_local[a_ij.row] += alpha * a_ij.value * x[a_ij.column];
            }
        }
    }

    // Combine the per‑thread contributions into the final y vector.
    for (size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        for (int t = 0; t < nthreads; ++t) {
            sum += local_y[t][i];
        }
        y[i] += sum;
    }
}
