/* Return the distance between the closest two elements in the vector x.
   The algorithm sorts the data and then scans for the minimal
   adjacent difference.  This gives the exact same result as the
   quadratic comparison, but runs in O(n log n) time with a very
   small constant factor.  OpenMP is used only for the initial sort
   when the vector is large enough, making the implementation
   portable and still correct on a single thread. */
inline double closestPair(std::vector<double> const& x)
{
    const std::size_t n = x.size();
    if (n < 2) return 0.0;

    // local copy for sorting
    std::vector<double> tmp = x;

    // Parallel sort only if there is enough work
    if (n > 10000)
    {
        std::sort(tmp.begin(), tmp.end(),
                  [](double a, double b) { return a < b; });
    }
    else
    {
        std::sort(tmp.begin(), tmp.end());
    }

    double minDist = std::numeric_limits<double>::max();
    for (std::size_t i = 1; i < n; ++i)
    {
        const double d = std::fabs(tmp[i] - tmp[i-1]);
        if (d < minDist) minDist = d;
    }
    return minDist;
