// Parallel, SIMD‑friendly 3‑point Jacobi stencil for 1‑D data.
// The algorithm is identical to the reference implementation but
// employs OpenMP and compiler intrinsics to maximise performance.
//
// Requires gcc‑8+ with -O2 and -fopenmp.
//
// Note: The result for boundary points is unchanged: missing
// neighbours are treated as 0.

inline void jacobi1D(std::vector<double> const& input,
                     std::vector<double> &output)
{
    // Ensure output is the same size as input
    if (output.size() != input.size())
        output.resize(input.size());

    const std::size_t N = input.size();
    if (N == 0) return;

    const double* in  = input.data();
          double* out = output.data();

    // First element (no left neighbour)
    out[0] = (in[0] + in[1]) / 3.0;

    // Main body – vectorised loop
    #pragma omp parallel for schedule(static, 32) // 32 = typical cache line
    for (std::size_t i = 1; i + 1 < N; ++i) {
        out[i] = (in[i-1] + in[i] + in[i+1]) / 3.0;
    }

    // Last element (no right neighbour)
    out[N-1] = (in[N-2] + in[N-1]) / 3.0;
}
