```cpp
#pragma once
#include <vector>
#include <cstddef>
#include <cstring>
#include <omp.h>

struct COOElement {
    size_t row;
    size_t column;
    double value;
};

/* Factorize the sparse matrix A into A=LU where L is a lower triangular matrix and U is an upper triangular
   matrix.  The matrix A is given in COO format (sparse), while L and U are returned as flat row‑major
   vectors of size N*N.  The algorithm is identical to the textbook LU decomposition without pivoting.
   In particular, the diagonal of L is exactly 1.0, and U may contain negative values on its diagonal
   when the input matrix is singular or non‑positive definite. */
void luFactorize(std::vector<COOElement> const& A,
                 std::vector<double>& L,
                 std::vector<double>& U,
                 size_t N)
{
    // Allocate a dense N×N matrix to hold the input data
    std::vector<double> fullA(N * N);
    std::fill(fullA.begin(), fullA.end(), 0.0);

    // Convert the COO list to dense format
    for (const auto& e : A) {
        fullA[e.row * N + e.column] = e.value;
    }

    // Initialise L with zeros
    std::fill(L.begin(), L.end(), 0.0);

    /* Main LU algorithm.
       Loop order is chosen to keep the inner dependencies only on previously
       processed rows/columns; this allows a natural parallelisation over the outer
       row index i.  The dependency on U[j][j] requires that the diagonal elements
       are finished before they are used by later rows, but since each row i
       depends only on rows < i, a simple parallel for over i with a barrier
       after each row is sufficient. */
#pragma omp parallel for schedule(static)
    for (long long ii = 0; ii < static_cast<long long>(N); ++ii) {
        size_t i = static_cast<size_t>(ii);
        // Tight loops for performance
        for (size_t j = 0; j < N; ++j) {
            double sum = 0.0;
            if (j >= i) {
                // Compute U[i][j]
                double val = fullA[i * N + j];
                for (size_t k = 0; k < i; ++k) {
                    val -= L[i * N + k] * U[k * N + j];
                }
                U[i * N + j] = val;
            }
            if (i > j) {
                // Compute L[i][j]
                double val = fullA[i * N + j];
                for (size_t k = 0; k < j; ++k) {
                    val -= L[i * N + k] * U[k * N + j];
                }
                L[i * N + j] = val / U[j * N + j];
            }
        }
        // Set the unit diagonal of L
        L[i * N + i] = 1.0;
    }
}
