static inline double triArea(Point const& a, Point const& b, Point const& c) noexcept
{
    return 0.5 * std::abs(a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
}

/* Return the area of the smallest triangle that can be formed by any 3 points.
   Example:
   input: [{0, 10}, {5, 5}, {1,0}, {-1, 1}, {-10, 0}]
   output: 5.5
*/
double smallestArea(std::vector<Point> const& points) noexcept
{
    const std::size_t n = points.size();
    if (n < 3)
        return 0.0;

    const double inf = std::numeric_limits<double>::infinity();
    double global_min = inf;

    // parallelize the outer two loops; inner loop is short so we keep it inside the
    // critical section size and let the compiler auto‑vectorize it
    #pragma omp parallel
    {
        double local_min = inf;
        #pragma omp for schedule(static, 1024) collapse(2) nowait
        for (std::size_t i = 0; i < n - 2; ++i)
        {
            for (std::size_t j = i + 1; j < n - 1; ++j)
            {
                for (std::size_t k = j + 1; k < n; ++k)
                {
                    const double area = triArea(points[i], points[j], points[k]);
                    if (area < local_min)
                        local_min = area;
                }
            }
        }
        #pragma omp critical
        {
            if (local_min < global_min)
                global_min = local_min;
        }
    }

    return global_min;
}
