/* Compute the prefix sum of the vector x into output.
   Example:
   input:  [1, 7, 4, 6, 6, 2]
   output: [1, 8,12,18,24,26]
   The implementation uses a parallel inclusive scan that is safe for any
   number of threads up to the hardware limit.
*/
void prefixSum(std::vector<int64_t> const& x, std::vector<int64_t> &output) {
    const std::size_t n = x.size();

    // Ensure output has the required size
    output.resize(n);

    if (n == 0) return;

    // Temporary buffer to hold local prefixes
    std::vector<int64_t> local(n);

    // --- 1st pass: compute local prefix sums in each chunk ---
    const std::size_t num_threads = std::min(8ULL, (std::size_t) omp_get_max_threads());
    const std::size_t chunk = (n + num_threads - 1) / num_threads; // ceil

    #pragma omp parallel
    {
        const std::size_t tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        if (start < end) {
            int64_t sum = 0;
            for (std::size_t i = start; i < end; ++i) {
                sum += x[i];
                local[i] = sum;
            }
        }
    }

    // --- 2nd pass: compute block sums (the last element of each chunk) ---
    std::vector<int64_t> block_sums(num_threads, 0);
    for (std::size_t tid = 0; tid < num_threads; ++tid) {
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        if (end > start) block_sums[tid] = local[end - 1];
    }

    // Prefix sum of block sums (exclusive) to obtain offsets
    std::vector<int64_t> offsets(num_threads, 0);
    if (!offsets.empty()) {
        offsets[0] = 0;
        for (std::size_t i = 1; i < num_threads; ++i)
            offsets[i] = offsets[i-1] + block_sums[i-1];
    }

    // --- 3rd pass: add inherited offset to each chunk ---
    #pragma omp parallel
    {
        const std::size_t tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);
        const int64_t offset = offsets[tid];

        for (std::size_t i = start; i < end; ++i)
            output[i] = local[i] + offset;
    }
}
