/* Convolve the 3×3 edge kernel with a square NxN grayscale image.
 * imageIn and imageOut are row‐major 1D representations of the image.
 * The kernel is applied with zero padding outside the bounds.
 * The result is clipped to the range [0,255].
 */
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           size_t                 N) noexcept
{
