    if (imageOut.size() != imageIn.size())
        imageOut.resize(imageIn.size());

    const int stride = static_cast<int>(N);
    const int *src     = imageIn.data();
    int       *dst     = imageOut.data();

    #pragma omp parallel for collapse(2)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        for (int j = 0; j < static_cast<int>(N); ++j) {
            int sum = 0;

            // Manual unroll of 3×3 kernel (handled by compiler, but makes intent clear)
            // Row i-1
            if (i > 0) {
                int x = (i - 1) * stride;
                sum += -src[x + j - 1];
                sum += -src[x + j];
                sum += -src[x + j + 1];
            }
            // Row i
            {
                int x = i * stride;
                sum += -src[x + j - 1];
                sum +=  8 * src[x + j];
                sum += -src[x + j + 1];
            }
            // Row i+1
            if (i + 1 < static_cast<int>(N)) {
                int x = (i + 1) * stride;
                sum += -src[x + j - 1];
                sum += -src[x + j];
                sum += -src[x + j + 1];
            }

            dst[i * stride + j] = static_cast<int>(std::clamp(sum, 0, 255));
        }
    }
