#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
    /* allocate a contiguous dense matrix to reduce pointer chasing */
    double *matrix = new double[N * N]();
    double *b_copy = new double[N]();     // copy of b
    std::copy(b.begin(), b.end(), b_copy);

    /* fill matrix from COO entries (parallel) */
#pragma omp parallel for schedule(static)
    for (size_t idx = 0; idx < A.size(); ++idx) {
        const auto &e = A[idx];
        matrix[e.row * N + e.column] = e.value;
    }

    x.assign(N, 0.0);

    /* Gaussian elimination with partial pivoting */
    for (size_t i = 0; i < N; ++i) {
        /* find pivot row */
        size_t maxRow = i;
        double maxEl = std::abs(matrix[i * N + i]);
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxEl) {
                maxEl = val;
                maxRow = k;
            }
        }

        /* swap pivot row with current row (matrix + b vector) */
        if (maxRow != i) {
            for (size_t col = i; col < N; ++col) {
                std::swap(matrix[maxRow * N + col], matrix[i * N + col]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* eliminate below */
#pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double c = -matrix[k * N + i] / matrix[i * N + i];
            if (c == 0.0) continue;          // nothing to do
            for (size_t j = i; j < N; ++j) {
                if (i == j) {
                    matrix[k * N + j] = 0.0;
                } else {
                    matrix[k * N + j] += c * matrix[i * N + j];
                }
            }
            b_copy[k] += c * b_copy[i];
        }
    }

    /* back substitution */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i] / matrix[i * N + i];
        x[i] = sum;
        for (int k = i - 1; k >= 0; --k) {
            b_copy[k] -= matrix[k * N + i] * sum;
        }
    }

    delete[] matrix;
    delete[] b_copy;
}
