        sin_tab[k] = std::sin(angle);
    }
}

inline void dft(const std::vector<double> &x,
                std::vector<std::complex<double>> &output) {
    const int N = static_cast<int>(x.size());
    output.assign(N, {0.0, 0.0});               // fast resize and init

    // 2×N tables – reuse them to avoid repeated trigonometric calls
    std::vector<double> sin_tab(N), cos_tab(N);
    precompute_sincos(N, sin_tab.data(), cos_tab.data());

    // Use OpenMP to parallelise the outer loop (each k is independent)
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        double re = 0.0, im = 0.0;
        const double* xptr = x.data();

        // Vectorised inner loop – process 4 elements at a time
        int n = 0;
        const int vec_len = 4;
        for (; n <= N - vec_len; n += vec_len) {
            __m256d xn = _mm256_loadu_pd(&xptr[n]);                       // x[n..n+3]
            // Compute angles for this block
            __m256d kn  = _mm256_set_pd(static_cast<double>(n+3), static_cast<double>(n+2),
                                        static_cast<double>(n+1), static_cast<double>(n));
            __m256d kkn = _mm256_mul_pd(kn, _mm256_set1_pd(static_cast<double>(k)));
            __m256d sin_tab_vec = _mm256_set_pd(sin_tab[n+3], sin_tab[n+2],
                                                sin_tab[n+1], sin_tab[n]);
            __m256d cos_tab_vec = _mm256_set_pd(cos_tab[n+3], cos_tab[n+2],
                                                cos_tab[n+1], cos_tab[n]);

            // Complex multiplication xn * (cos - i*sin)
            __m256d re_part = _mm256_mul_pd(xn, cos_tab_vec);
            __m256d im_part = _mm256_mul_pd(xn, sin_tab_vec);

            // Accumulate
            __m256d re_acc  = _mm256_loadu_pd(&re);          // re stored in little‑endian
            __m256d im_acc  = _mm256_loadu_pd(&im);

            re_acc = _mm256_add_pd(re_acc, re_part);
            im_acc = _mm256_sub_pd(im_acc, im_part);        // note the minus for sin

            // Store back
            _mm256_storeu_pd(&re, re_acc);
            _mm256_storeu_pd(&im, im_acc);
        }
        // Remainder scalar
        for (; n < N; ++n) {
            double c = cos_tab[n * k % N];
            double s = sin_tab[n * k % N];
            re += xptr[n] * c;
            im -= xptr[n] * s;
        }
        output[k] = std::complex<double>(re, im);
    }
}
