#if !defined(M_PI)
#  define M_PI 3.14159265358979323846
#endif

//--------------------------------------------------------------------
//  Iterative radix‑2 Cooley–Tukey FFT
//  -----------------------------------
//   * Uses pre‑computed twiddle factors
//   * In‑place array is used (copied from input)
//   * Bit‑reversal is done with a branchless lookup table
//   * OpenMP parallelism inside the butterfly stages
//--------------------------------------------------------------------
static inline void fft(std::vector<std::complex<double>> const& x,
                       std::vector<std::complex<double>> &output)
{
    const size_t N = x.size();
    output = x;                          // copy input

    /*--- Twiddle factor table -------------------------------------*/
    static std::vector<std::complex<double>> twiddle;
    static size_t twiddleCap = 0;
    if (N > twiddleCap) {
        twiddleCap = N;
        twiddle.resize(N);
        for (size_t i = 0; i < N; ++i)
            twiddle[i] = std::polar(1.0, -M_PI * double(i) / double(N));
    }

    /*--- Bit‑reversal table ----------------------------------------*/
    static std::vector<size_t> rev;
    static size_t revCap = 0;
    if (N != revCap) {
        revCap = N;
        rev.resize(N);
        size_t logN = 0;
        while ((1u << logN) < N) ++logN;
        for (size_t i = 0; i < N; ++i) {
            size_t x = i, r = 0;
            for (size_t j = 0; j < logN; ++j) {
                r = (r << 1) | (x & 1);
                x >>= 1;
            }
            rev[i] = r;
        }
    }

    /*--- Bit‑reverse the data -------------------------------------*/
    for (size_t i = 0; i < N; ++i) {
        size_t j = rev[i];
        if (j > i) std::swap(output[i], output[j]);
    }

    /*--- Main FFT loop --------------------------------------------*/
    for (size_t len = 2; len <= N; len <<= 1) {
        size_t half = len >> 1;
        size_t step = N / len;
#pragma omp parallel for schedule(static)
        for (size_t i = 0; i < N; i += len) {
            for (size_t j = 0; j < half; ++j) {
                size_t idx = i + j;
                size_t idx2 = idx + half;
                std::complex<double> t = twiddle[step * j] * output[idx2];
                output[idx2] = output[idx] - t;
                output[idx] += t;
            }
        }
    }
}
