struct Point {
    double x, y;
};

/* Convex Hull – Monotone Chain (O(n log n))
   The implementation is a lightweight, inlined version that avoids
   extraneous function calls and temporary objects.  It produces the
   same hull ordering as the reference algorithm.
*/
inline __attribute__((always_inline)) double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

inline void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    // Copy and sort input points by x, then y
    std::vector<Point> sorted(points.begin(), points.end());
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) noexcept {
                  return (a.x < b.x) || (a.x == b.x && a.y < b.y);
              });

    // Upper bound size is 2*n (no more than that is needed)
    std::vector<Point> buf;
    buf.resize(2 * n);

    std::size_t k = 0;

    // Build lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(buf[k - 2], buf[k - 1], sorted[i]) <= 0.0) {
            --k;
        }
        buf[k++] = sorted[i];
    }

    // Build upper hull
    std::size_t t = k + 1;
    for (std::size_t i = n; i-- > 1;) {          // i from n-1 downto 1
        while (k >= t && cross(buf[k - 2], buf[k - 1], sorted[i - 1]) <= 0.0) {
            --k;
        }
        buf[k++] = sorted[i - 1];
    }

    // Remove duplicate last point
    buf.resize(k - 1);

    hull.swap(buf);  // Avoid copy; result is now in hull
}
