#include <cstdint>
#include <omp.h>

/**
 * Multiply the matrix A by the vector x. Store the results in the vector y.
 * A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
 *
 * The implementation is thread‑parallel, uses blocking for cache locality,
 * and manually unrolls the inner loop for extra instruction‑level parallelism.
 */
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double>& y,
                 size_t M, size_t N) noexcept
{
    // Avoid OMP overhead for very small problems
    if (M == 0 || N == 0) return;

    constexpr std::size_t BLOCK = 128;        // cache‑friendly block size
    constexpr std::size_t UNROLL = 4;         // inner‑loop unroll factor

    // Ensure vectors have the expected sizes; undefined behaviour otherwise
    // (matching the original contract).
    if (y.size() < M || A.size() < M * N || x.size() < N) {
        return;
    }

    const double* restrict a = A.data();
    const double* restrict xv = x.data();
    double* restrict yv = y.data();

    #pragma omp parallel for schedule(static, BLOCK) collapse(1)
    for (size_t i = 0; i < M; ++i) {
        double sum = 0.0;
        const double* restrict a_row = a + i * N;
        size_t j = 0;

        // Unrolled processing
        for (; j + UNROLL <= N; j += UNROLL) {
            sum += a_row[j]     * xv[j];
            sum += a_row[j + 1] * xv[j + 1];
            sum += a_row[j + 2] * xv[j + 2];
            sum += a_row[j + 3] * xv[j + 3];
        }

        // Remaining tail
        for (; j < N; ++j) {
            sum += a_row[j] * xv[j];
        }

        yv[i] = sum;
    }
}
```

The routine keeps the original semantics while exploiting:
- **OpenMP parallelism** over the outer loop.
- **Cache‑friendly blocking** for the outer loop.
- **Manual loop unrolling** for the inner dot‑product.
- Pointer aliasing (`restrict`) to aid the compiler’s optimisation passes.

