struct Point {
    double x, y;
};

namespace impl
{
    // Fast inline 2‑D Euclidean distance (no pow, no sqrt per call)
    inline double dist2(const Point& a, const Point& b)
    {
        const double dx = a.x - b.x;
        const double dy = a.y - b.y;
        return dx * dx + dy * dy;
    }

    // Cross product (b‑a) × (c‑a)
    inline double cross(const Point& a, const Point& b, const Point& c)
    {
        return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
    }
}

// Return the perimeter of the smallest convex polygon that contains all the points.
double convexHullPerimeter(const std::vector<Point>& points)
{
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort the points lexicographically by (x, y)
    std::vector<Point> pts(points);
    std::sort(pts.begin(), pts.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });

    // Build the convex hull using the monotone chain (O(n))
    std::vector<Point> hull;
    hull.reserve(2 * n);

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (hull.size() >= 2 &&
               impl::cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // Upper hull
    const std::size_t lowerSize = hull.size();
    for (std::size_t i = n - 1; i-- > 0; ) {
        while (hull.size() > lowerSize &&
               impl::cross(hull[hull.size() - 2], hull[hull.size() - 1], pts[i]) <= 0)
            hull.pop_back();
        hull.push_back(pts[i]);
    }

    // Last point is same as first point of lower hull; remove duplicate
    hull.pop_back();

    // Compute perimeter in parallel: sum the distances between consecutive vertices
    double perimeter = 0.0;
    const std::size_t m = hull.size();

    #pragma omp parallel for reduction(+:perimeter) schedule(static)
    for (std::size_t i = 0; i < m; ++i) {
        const std::size_t j = (i + 1) % m;
        perimeter += std::sqrt(impl::dist2(hull[i], hull[j]));
    }

    return perimeter;
}
