inline void ranks(const std::vector<float>& x, std::vector<std::size_t>& ranks_) {
    const std::size_t n = x.size();
    if (n == 0) {
        ranks_.clear();
        return;
    }

    // Resize the output if necessary.
    if (ranks_.size() < n)
        ranks_.resize(n);

    // Create an index array 0 … n-1.
    std::vector<std::size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    // Sort indices by the corresponding values in `x`.  The comparator
    // is a plain function pointer to avoid any overhead associated with a
    // lambda capture.
    struct Compare {
        const std::vector<float>* pub;
        bool operator()(const std::size_t i1, const std::size_t i2) const {
            return (*pub)[i1] < (*pub)[i2];
        }
    } comp{&x};

    std::sort(idx.begin(), idx.end(), comp);

    // Build the rank array.
    for (std::size_t i = 0; i < n; ++i)
        ranks_[idx[i]] = i;
}
