/*!
 * @brief  For every cell set it to 1 iff it has exactly one neighbour that is 1.
 *
 *        For a cell at position (i,j) the neighbours considered are
 *          (i-1,j), (i+1,j), (i,j-1) and (i,j+1) (if they exist).
 *
 *        The input and output grids are linearised row‑major vectors of
 *        length N*N. The function guarantees to give the same result as
 *        the reference implementation in the repository.
 */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int>       &output,
                     size_t                   N) noexcept
{
    // Ensure the output vector is correctly sized
    if (output.size() != N * N) output.resize(N * N);

    // Pointers for fast access (no bounds checks inside the loops)
    const int *restrict inp = input.data();
          int *restrict out = output.data();
    const size_t Nsq = N * N;

    // Parallelise over external rows.  Static scheduling gives a good
    // load balance for the typical moderate sized N (e.g. 512–4096).
    #pragma omp parallel for schedule(static) collapse(1) if (Nsq > 1024)
    for (size_t i = 0; i < N; ++i)
    {
        const size_t rowOffset = i * N;
        const size_t prevRow   = (i > 0)   ? (rowOffset - N) : static_cast<size_t>(-1);
        const size_t nextRow   = (i < N-1) ? (rowOffset + N) : static_cast<size_t>(-1);

        for (size_t j = 0; j < N; ++j)
        {
            int count = 0;

            if (prevRow != static_cast<size_t>(-1) && inp[prevRow + j] == 1) ++count;
            if (nextRow != static_cast<size_t>(-1) && inp[nextRow + j] == 1) ++count;
            if (j > 0         && inp[rowOffset + j - 1] == 1)          ++count;
            if (j < N - 1     && inp[rowOffset + j + 1] == 1)          ++count;

            out[rowOffset + j] = (count == 1) ? 1 : 0;
        }
    }
}
