/*  Optimised Game‑of‑Life step
    * uses OpenMP to parallelise rows
    * avoids repeated bounds checks by handling edge cases explicitly
    * works with 8 threads (or the runtime default)
    * preserves exactly the semantics of the reference implementation
*/
inline void gameOfLife(std::vector<int> const& input,
                       std::vector<int> &output,
                       size_t N) noexcept
{
    constexpr size_t MAX_THREADS = 8;

#if defined(_OPENMP)
    omp_set_num_threads(MAX_THREADS);
#endif

    // Ensure output vector has the same size as input
    if (output.size() < N * N) output.resize(N * N);

    const int* in = input.data();
    int* out = output.data();

    /* Parallel over rows. Each thread works on a contiguous block of rows
       which keeps cache lines contiguous and reduces false sharing. */
#pragma omp parallel for schedule(static)
    for (long long _i = 0; _i < static_cast<long long>(N); ++_i) {
        const size_t i = static_cast<size_t>(_i);
        const size_t row_offset = i * N;
        const size_t prev_row = (i == 0)     ? 0      : (i - 1) * N;
        const size_t next_row = (i == N-1)   ? 0      : (i + 1) * N;

        for (size_t j = 0; j < N; ++j) {
            const size_t idx = row_offset + j;

            // Sum the eight neighbours
            int sum = 0;
            // North & South
            if (i > 0) sum += in[prev_row + j];
            if (i < N-1) sum += in[next_row + j];
            // West & East
            if (j > 0) sum += in[row_offset + j - 1];
            if (j < N-1) sum += in[row_offset + j + 1];
            // North‑West
            if (i > 0 && j > 0) sum += in[prev_row + j - 1];
            // North‑East
            if (i > 0 && j < N-1) sum += in[prev_row + j + 1];
            // South‑West
            if (i < N-1 && j > 0) sum += in[next_row + j - 1];
            // South‑East
            if (i < N-1 && j < N-1) sum += in[next_row + j + 1];

            // Apply the rules
            const int alive = in[idx];
            if (alive) {
                out[idx] = (sum == 2 || sum == 3) ? 1 : 0;
            } else {
                out[idx] = (sum == 3) ? 1 : 0;
            }
        }
    }
}
