/* Factorize the matrix A into A = L·U where
   L is lower‑triangular (unit diagonal) and U is upper‑triangular.
   The result is stored in place in A, row‑major order.
   Example:
     input : [[4, 3], [6, 3]]
     output: [[4, 3], [1.5, -1.5]]            */
void luFactorize(std::vector<double> &A, const std::size_t N) {
    // early exit for empty matrix
    if (N == 0) return;

    for (std::size_t k = 0; k < N; ++k) {
        const double pk = A[k * N + k];
        const double *rowk = &A[k * N];

        // Parallelize over the rows below the pivot row.
        #pragma omp parallel for schedule(static)
        for (std::size_t i = k + 1; i < N; ++i) {
            double *rowi = &A[i * N];
            const double factor = rowi[k] / pk;
            rowi[k] = factor;

            // Update the rest of the row once the factor is known.
            for (std::size_t j = k + 1; j < N; ++j) {
                rowi[j] -= factor * rowk[j];
            }
        }
    }
}
