static void fft_impl(std::vector<std::complex<double>>& buf, unsigned int N)
{
    // twiddle tables – computed once per N
    static std::vector<std::vector<std::complex<double>>> twiddles;
    static std::vector<unsigned int> rev;
    static std::vector<unsigned int> rev_pos;
    static unsigned int lastN = 0;

    if (N != lastN)
    {
        lastN = N;
        const unsigned int logN = static_cast<unsigned int>(std::ceil(std::log2(N)));

        // ---- twiddle factors ----
        twiddles.resize(logN);
        for (unsigned int s = 0; s < logN; ++s)
        {
            const unsigned int m = 1u << s;
            twiddles[s].resize(m);
            const double angle = -M_PI / m;
            for (unsigned int k = 0; k < m; ++k)
                twiddles[s][k] = std::complex<double>(std::cos(k * angle), std::sin(k * angle));
        }

        // ---- bit reversal ----
        rev.resize(N);
        for (unsigned int i = 0; i < N; ++i)
        {
            unsigned int x = i;
            x = (((x & 0xaaaaaaaa) >> 1) | ((x & 0x55555555) << 1));
            x = (((x & 0xcccccccc) >> 2) | ((x & 0x33333333) << 2));
            x = (((x & 0xf0f0f0f0) >> 4) | ((x & 0x0f0f0f0f) << 4));
            x = (((x & 0xff00ff00) >> 8) | ((x & 0x00ff00ff) << 8));
            x = ((x >> 16) | (x << 16)) >> (32 - logN);
            rev[i] = x;
        }

        // pre‑compute distance per stage to speed indexing
        rev_pos.resize(N);
        for (unsigned int i = 0; i < N; ++i)
            rev_pos[rev[i]] = i;
    }

    // ---- bit‑reversal permutation (parallel) ----
    #pragma omp parallel for schedule(static)
    for (unsigned int i = 0; i < N; ++i)
    {
        if (rev[i] > i)
        {
            std::swap(buf[i], buf[rev[i]]);
        }
    }

    // ---- iterative FFT ----
    for (unsigned int s = 0; s < rev.size(); ++s)
    {
        const unsigned int m = 1u << s;      // butterfly size
        const unsigned int step = m << 1;    // stride between butterflies
        const std::complex<double>* w = twiddles[s].data();

        #pragma omp parallel for schedule(static)
        for (unsigned int k = 0; k < N; k += step)
        {
            for (unsigned int j = 0; j < m; ++j)
            {
                const std::complex<double> t = w[j] * buf[k + j + m];
                const std::complex<double> u = buf[k + j];
                buf[k + j] = u + t;
                buf[k + j + m] = u - t;
            }
        }
    }
}

inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<double>& r,
                std::vector<double>& i)
{
    const std::size_t N = x.size();
    r.resize(N);
    i.resize(N);

    // copy into temporary buffer
    std::vector<std::complex<double>> buf(x.begin(), x.end());

    fft_impl(buf, static_cast<unsigned int>(N));

    // split into real / imag
    #pragma omp parallel for schedule(static)
    for (std::size_t j = 0; j < N; ++j)
    {
        r[j] = buf[j].real();
        i[j] = buf[j].imag();
    }
}
