#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix.
   The matrices are stored in row‑major order.
   Example:
     input:  A = [[1, -1, 2], [0, -2, 1]]
             B = [[4, 1], [-1, 0], [2, 2]]
     output: C = [[9, 5], [4, 2]]
*/
void gemm(std::vector<double> const& A,
          std::vector<double> const& B,
          std::vector<double> &C,
          size_t M, size_t K, size_t N)
{
    /* Ensure the result buffer is zeroed (gemm in the original
       accumulates into C, so the caller must supply a zeroed buffer).
       Still perform it here for robustness. */
    std::fill(C.begin(), C.end(), 0.0);

    // Choose block sizes that fit in L1/L2 cache; tune these if needed.
    const size_t blockM = 64;  // rows of A / C
    const size_t blockN = 64;  // cols of B / C
    const size_t blockK = 64;  // cols of A / rows of B

    // Parallelize over the outermost block of rows.
    #pragma omp parallel for schedule(dynamic)
    for (size_t i0 = 0; i0 < M; i0 += blockM) {
        size_t i_max = std::min(i0 + blockM, M);
        for (size_t j0 = 0; j0 < N; j0 += blockN) {
            size_t j_max = std::min(j0 + blockN, N);
            for (size_t k0 = 0; k0 < K; k0 += blockK) {
                size_t k_max = std::min(k0 + blockK, K);

                /* Loop order i -> k -> j gives straight‑forward access
                   to A[i*K + k] and B[k*N + j] but is not the most cache‑friendly.
                   We use i -> j -> k inside the block to exploit spatial locality. */
                for (size_t i = i0; i < i_max; ++i) {
                    double const* A_row = &A[i*K];
                    double* C_row = &C[i*N];
                    for (size_t j = j0; j < j_max; ++j) {
                        double sum = C_row[j];
                        for (size_t k = k0; k < k_max; ++k) {
                            sum += A_row[k] * B[k*N + j];
                        }
                        C_row[j] = sum;
                    }
                }
            }
        }
    }
}
