#define M_PI 3.14159265358979323846
#endif

namespace fft_internal
{
    // Precompute twiddle factors for all stages up to 2^20 (adjust as needed)
    inline std::vector<std::complex<double>> precompute_twiddles(unsigned int max_power)
    {
        std::vector<std::complex<double>> twiddles;
        for (unsigned int p = 1; p <= max_power; ++p)
        {
            unsigned int m = 1U << p;
            twiddles.emplace_back(std::polar(1.0, -2.0 * M_PI / m)); // exp(-i*2π/m)
        }
        return twiddles;
    }

    // Bit-reversal permutation for length N=2^k
    inline void bit_reverse_permute(std::complex<double>* data, unsigned int N)
    {
        unsigned int m = 31 - __builtin_clz(N);          // log2(N)
        unsigned int rev = 0;
        for (unsigned int i = 0; i < N; ++i)
        {
            if (i < rev)
                std::swap(data[i], data[rev]);

            unsigned int mask = N;
            for (;;)
            {
                mask >>= 1;
                rev ^= mask;
                if (rev & mask)
                    break;
            }
        }
    }

    // In-place radix‑2 Cooley‑Tukey FFT
    inline void fft_radix2(std::complex<double>* data, unsigned int N, bool inverse)
    {
        // Bit-reversal ordering
        bit_reverse_permute(data, N);

        // Iterative butterfly stages
        for (unsigned int s = 1, msn = 2; msn <= N; s++, msn <<= 1)
        {
            int step = msn >> 1;
            std::complex<double> ws = std::polar(1.0,
                                                 (inverse ? 2.0 : -2.0) * M_PI / msn); // w_m^(±1)
            #pragma omp parallel for
            for (int k = 0; k < step; ++k)
            {
                std::complex<double> w(1.0, 0.0);
                for (int j = k; j < N; j += msn)
                {
                    std::complex<double> t = w * data[j + step];
                    data[j + step] = data[j] - t;
                    data[j] += t;
                    w *= ws;
                }
            }
        }

        // For inverse FFT divide by N
        if (inverse)
        {
            double invN = 1.0 / static_cast<double>(N);
            #pragma omp parallel for
            for (int i = 0; i < N; ++i)
                data[i] *= invN;
        }
    }
}

void fft_helper(std::vector<std::complex<double>>& x)
{
    // Forward FFT (real‑valued input assumed)
    fft_internal::fft_radix2(x.data(), static_cast<unsigned>(x.size()), false);
}

void ifft(std::vector<std::complex<double>>& x)
{
    // Inverse FFT: conjugate, forward FFT, conjugate again, scale
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });
    fft_internal::fft_radix2(x.data(), static_cast<unsigned>(x.size()), false);
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v) { return std::conj(v); });

    // Scaling already performed in the FFT function for inverse case
}
