#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row‑major. x and b have N elements.
   Example:
      A = [[1,4,2], [1,2,3], [2,1,3]], b=[11,11,13]  -> x=[3,1,2]
   The function keeps the exact behaviour of the reference implementation but
   is tuned for speed on a modern x86‑64 machine with 8 threads and gcc
   (O2, OpenMP).  No external libraries are used.
*/
inline void solveLinearSystem(const std::vector<double> &A,
                              const std::vector<double> &b,
                              std::vector<double> &x,
                              std::size_t N)
{
    // Create local copies so we can modify the matrix
    std::vector<double> Acopy(A);
    std::vector<double> bcopy(b);

    // Gaussian elimination with partial pivoting removed (original code assumed
    // non‑zero pivot).  We retain the same behaviour by aborting on zero pivot.
    for (std::size_t i = 0; i < N - 1; ++i) {
        const std::size_t idx = i * N + i;
        const double pivot = Acopy[idx];

        if (pivot == 0.0) return;                // early exit exactly as original

        const double invPivot = 1.0 / pivot;

        // Parallelise the elimination of rows below the pivot.
        // Each thread works on a disjoint set of rows.
        #pragma omp parallel for schedule(static)
        for (std::size_t j = i + 1; j < N; ++j) {
            const std::size_t jrow = j * N + i;
            const double factor = Acopy[jrow] * invPivot;  // Acopy[j][i] / pivot

            // Update the current row (elements i..N-1)
            std::size_t k = i;
            double *row_j = &Acopy[jrow];
            const double *row_i = &Acopy[idx];
            for (; k < N; ++k) {
                row_j[k - i] -= factor * row_i[k - i];
            }
            // Update the RHS
            bcopy[j] -= factor * bcopy[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = 0.0;
        const double *row_i = &Acopy[i * N];
        for (std::size_t j = i + 1; j < N; ++j) {
            sum += row_i[j] * x[j];
        }
        x[i] = (bcopy[i] - sum) / Acopy[i * N + i];
    }
}
