```cpp
#pragma once
#include <vector>
#include <cmath>
#include <cstddef>
#include <limits>
#include <algorithm>
#include <omp.h>

/*
   Return the index of the value in the vector x that is closest to the mathematical constant PI.
   Uses M_PI for the value of PI.  The function is fully deterministic and will always return
   the first (smallest index) element in the event of a tie.
*/
inline size_t findClosestToPi(const std::vector<double>& x)
{
    const double pi = M_PI;
    const std::size_t N = x.size();

    // Handle empty vector gracefully – undefined in the spec, but return 0.
    if (N == 0) return 0;

    size_t bestIdx = 0;
    double bestDiff = std::abs(x[0] - pi);

    /* The loop is small enough that the overhead of spawning OpenMP threads
       is not justified, yet we still want to exploit vectorisation on the
       inner loop.  The `#pragma omp simd` directive hints the compiler to
       generate SIMD code for the loop below while preserving the order of
       execution so that the first occurrence of a minimal difference
       remains the chosen index. */
    #pragma omp simd
    for (std::size_t i = 1; i < N; ++i)
    {
        const double diff = std::abs(x[i] - pi);
        if (diff < bestDiff)
        {
            bestDiff = diff;
            bestIdx  = i;
        }
    }

    return bestIdx;
}
